import "./SummaryCard.css";

function SummaryCard() {
    return (
        <>
        <div className="summary-container">
            <p className="main-heading">Summary</p>
            <div className="income">
                <p className="container-heading">Income</p>
                <p className="text">₹100000</p>
            </div>
            <div className="expenses">
                <p className="container-heading">Expenses</p>
                <p className="text">₹40000</p>
            </div>
            <div className="balance">
                <p className="container-heading">Balance</p>
                <p className="text">₹60000</p>
            </div>
        </div>
        </>
    )
};

export default SummaryCard;
